import Link from "next/link";
import {
  ArrowRight,
  CircleCheckBig,
  OctagonX,
  Truck,
} from "lucide-react";
import { Card, CardContent } from "@ui/components/card";
import { Button } from "@ui/components/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@ui/components/table";

export type OrderStatusTableRow = {
  /** Khóa React (vd. id số đơn); hiển thị mã đơn ở cột đầu dùng `orderCode`. */
  rowKey: string;
  orderCode: string;
  date: string;
  statusText: string;
  etaOrTotal: string;
  status: "shipping" | "completed" | "cancelled";
  href: string;
  ctaLabel: string;
};

export function OrderStatusTable({ rows }: { rows: OrderStatusTableRow[] }) {
  return (
    <Card className="border-border py-0 overflow-hidden">
      <CardContent className="p-0 overflow-x-auto">
        <Table>
          <TableHeader>
            <TableRow className="bg-muted/30">
              <TableHead className="pl-6">Mã đơn</TableHead>
              <TableHead>Ngày đặt</TableHead>
              <TableHead>Trạng thái</TableHead>
              <TableHead>Thông tin</TableHead>
              <TableHead className="text-right pr-6">Hành động</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {rows.map((row) => (
              <TableRow key={row.rowKey}>
                <TableCell className="pl-6 font-bold">{row.orderCode}</TableCell>
                <TableCell className="text-muted-foreground">{row.date}</TableCell>
                <TableCell>
                  <span
                    className={`inline-flex items-center gap-2 px-2.5 py-1 rounded-full text-xs font-bold ${
                      row.status === "shipping"
                        ? "bg-primary/10 text-primary"
                        : row.status === "completed"
                          ? "bg-success/15 text-success"
                          : "bg-destructive/10 text-destructive"
                    }`}
                  >
                    {row.status === "shipping" ? (
                      <Truck className="w-3.5 h-3.5" />
                    ) : row.status === "completed" ? (
                      <CircleCheckBig className="w-3.5 h-3.5" />
                    ) : (
                      <OctagonX className="w-3.5 h-3.5" />
                    )}
                    {row.statusText}
                  </span>
                </TableCell>
                <TableCell className="text-muted-foreground">{row.etaOrTotal}</TableCell>
                <TableCell className="text-right pr-6">
                  <Link href={row.href}>
                    <Button variant="outline" size="sm">
                      {row.ctaLabel}
                      <ArrowRight className="w-4 h-4 ml-1.5" />
                    </Button>
                  </Link>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

src/components/shared/product-card.tsx.content:
"use client";

import Link from "next/link";
import { ArrowRight, Plus, ShoppingCart, Tag } from "lucide-react";
import { Card, CardContent, CardFooter } from "@ui/components/card";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import { Heading, Text } from "@ui/components/typography";

type ProductCardVariant = "catalog" | "flash";

type ProductCardProps = {
  variant: ProductCardVariant;
  href: string;
  name: string;
  image: string;
  price: string;
  originalPrice?: string;
  category?: string;
  minQty?: string;
  coupon?: string;
  discountLabel?: string;
  soldText?: string;
  progressPercent?: number;
  topRightBadge?: string;
  primaryCtaLabel?: string;
  onAddToCart?: () => void;
};

export function ProductCard({
  variant,
  href,
  name,
  image,
  price,
  originalPrice,
  category,
  minQty,
  coupon,
  discountLabel,
  soldText,
  progressPercent,
  topRightBadge = "Chính hãng",
  primaryCtaLabel = "Xem chi tiết",
  onAddToCart,
}: ProductCardProps) {
  return (
    <Card className="py-0 border-outline-variant overflow-hidden group hover:shadow-xl transition-all duration-300 bg-background rounded-lg">
      <Link href={href} className={`block relative ${variant === "catalog" ? "w-full h-64" : "h-64"} bg-gradient-to-b from-white to-muted/20`}>
        <div className="w-full h-full rounded-lg bg-white/70 border border-outline-variant/30 shadow-inner flex items-center justify-center overflow-hidden">
          <img
            src={image}
            alt={name}
            className="w-full h-full rounded-lg object-cover drop-shadow-[0_10px_20px_rgba(0,0,0,0.18)] rounded-lg transition-transform duration-500 group-hover:scale-105"
          />
        </div>

        <div className="absolute top-4 right-4">
          <Badge variant="secondary" className="bg-background/90 backdrop-blur shadow-sm text-xs font-bold text-primary border border-primary/20">
            {topRightBadge}
          </Badge>
        </div>

        {coupon && variant === "catalog" && (
          <div className="absolute top-4 left-4 bg-warning/20 text-warning-foreground px-3 py-1.5 rounded-lg font-bold text-sm border border-warning/30 flex items-center gap-1.5 shadow-sm backdrop-blur-sm">
            <Tag className="w-4 h-4" />
            {coupon}
          </div>
        )}

        {discountLabel && variant === "flash" && (
          <div className="absolute top-4 left-4 bg-destructive text-white px-3 py-1.5 rounded-lg font-black text-sm shadow-lg">
            {discountLabel}
          </div>
        )}
      </Link>

      <CardContent className={`p-6 flex flex-col ${variant === "catalog" ? "h-[260px]" : "h-[245px]"} space-y-4`}>
        {category && (
          <div className="text-sm font-bold text-primary/80 uppercase tracking-widest">{category}</div>
        )}

        <Link href={href} className="group/title">
          <Heading
            as="h3"
            size="title"
            className={`line-clamp-2 leading-tight group-hover/title:text-primary transition-colors ${variant === "catalog" ? "min-h-[4rem]" : "min-h-[3.5rem]"}`}
          >
            {name}
          </Heading>
        </Link>

        <div className="mt-auto pt-4 border-t border-outline-variant/30 space-y-2">
          <div className="flex flex-wrap items-baseline gap-2">
            {originalPrice && (
              <Text variant="muted" className="line-through font-medium text-sm shrink-0">
                {originalPrice}
              </Text>
            )}
            <Heading as="span" size="title" color="primary" className="shrink-0">
              {price}
            </Heading>
          </div>

          {variant === "catalog" && minQty && (
            <div className="text-base font-bold text-primary mt-1 flex items-center gap-1">
              <Plus className="w-4 h-4" />
              {minQty}
            </div>
          )}

          {variant === "flash" && soldText && (
            <div className="space-y-2">
              <div className="flex justify-between text-sm font-bold">
                <Text as="span" variant="muted">{soldText}</Text>
                <Text as="span" variant="body" className="text-primary font-bold">Hot 🔥</Text>
              </div>
              <div className="h-3 bg-muted rounded-full overflow-hidden border border-border/50 p-0.5">
                <div
                  className="h-full bg-gradient-to-r from-primary to-teal-500 rounded-full"
                  style={{ width: `${Math.max(0, Math.min(100, progressPercent ?? 0))}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </CardContent>

      <CardFooter className={variant === "catalog" ? "" : undefined}>
        <div className={`w-full flex ${variant === "catalog" ? "items-center gap-2" : ""}`}>
          <Link href={href} className={variant === "catalog" ? "flex-1" : "w-full"}>
            <Button className="w-full h-14 rounded-lg font-bold text-lg shadow-lg hover:bg-primary/90 transition-all flex gap-2">
              <ArrowRight className="size-5" />
              {primaryCtaLabel}
            </Button>
          </Link>
          {variant === "catalog" && onAddToCart && (
            <Button
              className="h-14 w-14 rounded-lg shadow-lg hover:scale-110 transition-all hover:bg-primary/90"
              aria-label="Thêm vào giỏ"
              onClick={onAddToCart}
            >
              <ShoppingCart className="w-7 h-7" />
            </Button>
          )}
        </div>
      </CardFooter>
    </Card>
  );
}

src/components/shared/product-detail.tsx.content:
"use client";

import { useMemo, useState } from "react";
import Link from "next/link";
import {
  ArrowLeft,
  Package,
  ShoppingCart,
  Truck,
  Minus,
  Plus,
  AlertTriangle,
  CheckCircle2,
  Tag,
} from "lucide-react";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import { Card, CardContent } from "@ui/components/card";
import { toast } from "sonner";
import type { Product, ProductUnitType } from "@/lib/api";
import { formatVND } from "@/lib/format";
import { unitSellingAndListPrice } from "@/lib/product-price";
import { useCategoryBySlug } from "@/hooks/queries";
import { cartLineQuantity, useCart } from "@/hooks/use-cart";

type ProductDetailProps = {
  product: Product;
  backHref?: string;
  supportHref?: string;
};

export function ProductDetail({
  product,
  backHref = "/catalog",
  supportHref = "/support",
}: ProductDetailProps) {
  const { data: category } = useCategoryBySlug(product.category);
  const categoryLabel = category?.name ?? product.category;
  const cart = useCart();
  const fallbackUnit: ProductUnitType = useMemo(
    () => ({
      type: product.unit,
      label: product.unit,
      wholesalePrice: product.wholesalePrice,
      retailPrice: product.retailPrice,
      minWholesaleQty: 1,
      qtyPerUnit: 1,
    }),
    [product],
  );
  const units: ProductUnitType[] =
    product.unitTypes && product.unitTypes.length > 0
      ? product.unitTypes
      : [fallbackUnit];

  const [selectedUnit, setSelectedUnit] = useState<ProductUnitType>(units[0]!);
  const allImages = product.images ?? [];
  const [activeImage, setActiveImage] = useState<string | undefined>(allImages[0]);

  /** Luôn cho đặt từ 1; `minWholesaleQty` chỉ là ngưỡng áp giá KM. */
  const minPurchaseQty = 1;
  const minPromoQty =
    selectedUnit.minWholesaleQty > 0 ? selectedUnit.minWholesaleQty : 1;
  const maxQty = Math.max(
    1,
    Math.floor(product.stock / Math.max(selectedUnit.qtyPerUnit, 1)),
  );
  const [qty, setQty] = useState(1);

  const qtyInCart = cartLineQuantity(
    cart.lines,
    product.id,
    selectedUnit.type,
  );
  const pricingQty = qtyInCart + qty;

  const isWholesale = selectedUnit.wholesalePrice !== null;
  const { current: unitPrice, list: listPrice } = unitSellingAndListPrice(
    selectedUnit,
    pricingQty,
  );

  const totalUnits = qty * Math.max(selectedUnit.qtyPerUnit, 1);
  const totalPrice = unitPrice * qty;
  const stockWarning = totalUnits > product.stock * 0.8;
  const outOfStock = maxQty <= 0 || qty > maxQty;

  const handleQtyChange = (delta: number) => {
    setQty((prev) =>
      Math.max(minPurchaseQty, Math.min(prev + delta, maxQty)),
    );
  };

  const handleUnitChange = (u: ProductUnitType) => {
    setSelectedUnit(u);
    setQty(1);
  };

  const handleAddToCart = () => {
    if (outOfStock) return;
    cart.add(product, selectedUnit, qty);
    toast.success(`Đã thêm ${qty} ${selectedUnit.label} vào giỏ hàng`, {
      description: `${product.name} · Tổng: ${formatVND(totalPrice)}`,
    });
  };

  return (
    <>
      <Link href={backHref}>
        <Button variant="outline" className="rounded-lg">
          <ArrowLeft className="w-4 h-4 mr-2" /> Quay lại danh mục
        </Button>
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card className="rounded-lg border-outline-variant overflow-hidden">
          <CardContent className="p-6 space-y-4">
            <div className="aspect-square bg-gradient-to-b from-white to-muted/20 rounded-lg p-6 border border-outline-variant/30 shadow-inner flex items-center justify-center">
              {activeImage ? (
                <img
                  src={activeImage}
                  alt={product.name}
                  className="max-h-[88%] max-w-[88%] object-cover drop-shadow-[0_14px_24px_rgba(0,0,0,0.2)] rounded-lg transition-all duration-300"
                />
              ) : (
                <Package className="w-20 h-20 text-outline-variant" />
              )}
            </div>
            {allImages.length > 0 && (
              <div className="grid grid-cols-4 gap-2">
                {allImages.slice(0, 4).map((img) => (
                  <Button
                    key={img}
                    onClick={() => setActiveImage(img)}
                    className={`aspect-square h-auto rounded-lg p-1.5 border-2 transition-all overflow-hidden bg-white ${
                      activeImage === img
                        ? "border-primary shadow-md"
                        : "border-outline-variant/30 hover:border-primary/40"
                    }`}
                  >
                    <img src={img} alt={product.name} className="w-full h-full object-cover rounded-lg" />
                  </Button>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        <div className="space-y-5">
          <div className="flex flex-wrap items-center gap-2">
            <Badge className="bg-primary/10 text-primary border-primary/20 font-bold">
              {categoryLabel}
            </Badge>
            {product.coupons?.map((c) => (
              <Badge
                key={c}
                className="bg-destructive/10 text-destructive border-destructive/20 font-bold text-xs"
              >
                <Tag className="w-3 h-3 mr-1" />
                {c}
              </Badge>
            ))}
          </div>

          <h1 className="text-3xl font-black leading-tight tracking-tight">{product.name}</h1>
          {product.description && (
            <p className="text-base text-muted-foreground">{product.description}</p>
          )}

          {units.length > 1 && (
            <div className="space-y-2">
              <p className="text-xs font-bold text-on-surface-variant uppercase tracking-wide">
                Chọn loại đơn vị:
              </p>
              <div className="flex flex-wrap gap-2">
                {units.map((u) => {
                  const active = selectedUnit.type === u.type;
                  const isSi = u.wholesalePrice !== null;
                  const inCartU = cartLineQuantity(cart.lines, product.id, u.type);
                  const previewQty = inCartU + qty;
                  const { current, list } = unitSellingAndListPrice(
                    u,
                    previewQty,
                  );
                  return (
                    <Button
                      key={u.type}
                      onClick={() => handleUnitChange(u)}
                      className={`h-auto px-4 py-2 rounded-lg text-sm font-bold border flex-col items-start gap-0.5 transition-all ${
                        active
                          ? isSi
                            ? "bg-primary text-primary-foreground border-primary shadow-md"
                            : "bg-secondary text-secondary-foreground border-secondary shadow-md"
                          : "bg-background border-outline-variant text-on-surface-variant hover:bg-muted"
                      }`}
                    >
                      <span>{u.label}</span>
                      <span
                        className={`flex flex-wrap items-baseline gap-1 text-xs font-semibold ${active ? "opacity-90" : "text-primary"}`}
                      >
                        {list != null && (
                          <span className="line-through opacity-70">{formatVND(list)}</span>
                        )}
                        <span>{formatVND(current)}</span>
                        {isSi && (
                          <span className="ml-0.5 opacity-70">• Khuyến mãi</span>
                        )}
                      </span>
                    </Button>
                  );
                })}
              </div>
            </div>
          )}

          <div className="rounded-lg border border-outline-variant/40 bg-surface p-5 space-y-3">
            <div className="flex flex-wrap items-end gap-2 md:gap-3">
              {listPrice != null && (
                <p className="text-lg font-semibold text-muted-foreground line-through mb-1">
                  {formatVND(listPrice)}
                </p>
              )}
              <p className="text-4xl font-black text-primary">{formatVND(unitPrice)}</p>
              <p className="text-base text-muted-foreground mb-1">/ {selectedUnit.label}</p>
              {isWholesale && (
                <Badge
                  className={
                    listPrice != null
                      ? "mb-1 bg-primary/10 text-primary border-primary/20 font-bold"
                      : "mb-1 bg-secondary/10 text-secondary-foreground border-secondary/20 font-bold"
                  }
                >
                  {listPrice != null ? "Giá KM (đủ SL)" : "Giá ban đầu"}
                </Badge>
              )}
            </div>
            {qtyInCart > 0 && (
              <p className="text-xs text-muted-foreground font-medium">
                Trong giỏ:{" "}
                <span className="font-bold text-foreground">
                  {qtyInCart} {selectedUnit.type}
                </span>
                {" · "}
                Đang thêm:{" "}
                <span className="font-bold text-foreground">{qty}</span>
                {" → "}
                Tổng (áp giá):{" "}
                <span className="font-bold text-primary">{pricingQty}</span>
              </p>
            )}
            {isWholesale && minPromoQty > 1 && (
              <p className="text-sm text-on-surface-variant font-medium">
                Từ{" "}
                <span className="font-black text-primary">
                  {minPromoQty} {selectedUnit.type}
                </span>{" "}
                trở lên mới áp giá khuyến mãi; mua ít hơn vẫn được (giá ban đầu).
                {pricingQty < minPromoQty && (
                  <span className="block text-xs mt-1 text-muted-foreground">
                    Tổng sau khi thêm ({pricingQty}) vẫn chưa đủ điều kiện KM — có
                    thể đặt từ 1.
                  </span>
                )}
                {pricingQty >= minPromoQty && (
                  <span className="block text-xs mt-1 text-emerald-700 dark:text-emerald-400">
                    {qtyInCart > 0
                      ? `Đủ điều kiện KM khi gộp giỏ (${qtyInCart}) + lần này (${qty}) = ${pricingQty} ${selectedUnit.type}.`
                      : `Đủ điều kiện KM với ${pricingQty} ${selectedUnit.type}.`}
                  </span>
                )}
              </p>
            )}
            {totalPrice > 0 && (
              <div className="pt-2 border-t border-outline-variant/30 flex items-center justify-between">
                <p className="text-sm text-on-surface-variant font-medium">
                  Tổng cộng ({qty} {selectedUnit.type}
                  {selectedUnit.qtyPerUnit > 1
                    ? ` × ${selectedUnit.qtyPerUnit} ${product.unit}`
                    : ""}
                  ):
                </p>
                <p className="text-xl font-black text-primary">{formatVND(totalPrice)}</p>
              </div>
            )}
          </div>

          <div className="space-y-2">
            <p className="text-xs font-bold text-on-surface-variant uppercase tracking-wide">
              Số lượng đặt:
            </p>
            <div className="flex items-center gap-4">
              <div className="flex items-center border border-outline-variant rounded-lg overflow-hidden">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-12 w-12 rounded-none border-r border-outline-variant"
                  onClick={() => handleQtyChange(-1)}
                  disabled={qty <= minPurchaseQty}
                >
                  <Minus className="w-4 h-4" />
                </Button>
                <div className="w-16 text-center">
                  <p className="text-xl font-black text-foreground">{qty}</p>
                  <p className="text-[10px] text-on-surface-variant leading-none">
                    {selectedUnit.type}
                  </p>
                </div>
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-12 w-12 rounded-none border-l border-outline-variant"
                  onClick={() => handleQtyChange(1)}
                  disabled={outOfStock}
                >
                  <Plus className="w-4 h-4" />
                </Button>
              </div>
              <div className="text-sm text-on-surface-variant space-y-0.5">
                <p>
                  ={" "}
                  <span className="font-bold text-foreground">
                    {totalUnits.toLocaleString("vi-VN")}
                  </span>{" "}
                  {product.unit}
                </p>
                <p className="text-xs">
                  Tồn kho:{" "}
                  <span
                    className={`font-bold ${
                      outOfStock
                        ? "text-destructive"
                        : stockWarning
                          ? "text-warning"
                          : "text-success"
                    }`}
                  >
                    {product.stock} {product.unit}
                  </span>
                </p>
              </div>
            </div>
            {stockWarning && !outOfStock && (
              <div className="flex items-center gap-2 text-warning text-sm font-semibold bg-warning/10 px-3 py-2 rounded-lg">
                <AlertTriangle className="w-4 h-4 shrink-0" /> Sắp hết hàng – chỉ còn ít trong kho
              </div>
            )}
            {outOfStock && (
              <div className="flex items-center gap-2 text-destructive text-sm font-semibold bg-destructive/10 px-3 py-2 rounded-lg">
                <AlertTriangle className="w-4 h-4 shrink-0" /> Số lượng vượt quá tồn kho hiện tại
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 gap-3">
            <InfoItem label="Thương hiệu" value={product.brand ?? "—"} />
            <InfoItem label="Xuất xứ" value={product.origin ?? "—"} />
            <InfoItem label="Mã SKU" value={product.sku} />
            <InfoItem label="Tồn kho" value={`${product.stock} ${product.unit}`} />
          </div>

          <div className="flex flex-col sm:flex-row gap-3 pt-2">
            <Button
              className="h-14 rounded-lg px-8 font-black text-base flex-1"
              onClick={handleAddToCart}
              disabled={outOfStock}
            >
              <ShoppingCart className="w-5 h-5 mr-2" />
              {outOfStock ? "Hết hàng" : `Thêm vào giỏ – ${formatVND(totalPrice)}`}
            </Button>
            <Link href={supportHref}>
              <Button variant="outline" className="h-14 rounded-lg px-6 font-bold w-full sm:w-auto">
                <Truck className="w-4 h-4 mr-2" /> Tư vấn
              </Button>
            </Link>
          </div>

          {!outOfStock && (
            <div className="flex items-center gap-2 text-success text-sm font-semibold">
              <CheckCircle2 className="w-4 h-4" /> Còn hàng – giao trong hôm nay hoặc ngày mai
            </div>
          )}
        </div>
      </div>
    </>
  );
}

function InfoItem({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-lg border border-outline-variant/40 p-3 bg-background">
      <p className="text-xs uppercase tracking-wide text-muted-foreground">{label}</p>
      <p className="font-bold flex items-center gap-2 mt-1">
        <Package className="w-4 h-4 text-primary" />
        {value}
      </p>
    </div>
  );
}

