src/components/shared/store-auth-gate.ts.content:
"use client";

import { useEffect, type ReactNode } from "react";
import { usePathname, useRouter } from "next/navigation";
import { Loader2 } from "lucide-react";
import { useSession } from "@/hooks/use-session";
import { useClientReady } from "@/hooks/use-client-ready";
import { isStoreAuthPath, safeRelativeNext } from "@/lib/auth-routes";

function AuthRoutePlaceholder({ message }: { message: string }) {
  return (
    <div className="flex min-h-[min(70vh,calc(100vh-12rem))] w-full flex-1 flex-col items-center justify-center gap-3 text-muted-foreground">
      <Loader2 className="size-10 animate-spin text-primary" aria-hidden />
      <p className="text-sm">{message}</p>
    </div>
  );
}

/**
 * Chặn người đã đăng nhập quay lại /login hoặc /register (kể cả nút Back / gõ URL).
 * Giữ tham số `next` hợp lệ khi rời /login.
 */
export function StoreAuthGate({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const session = useSession();
  const clientReady = useClientReady();
  const onAuthRoute = isStoreAuthPath(pathname);

  useEffect(() => {
    if (!clientReady || !onAuthRoute || !session) return;
    const raw =
      typeof window !== "undefined"
        ? new URLSearchParams(window.location.search).get("next")
        : null;
    router.replace(safeRelativeNext(raw));
  }, [clientReady, onAuthRoute, session, router]);

  if (!onAuthRoute) {
    return <>{children}</>;
  }

  if (!clientReady) {
    return <AuthRoutePlaceholder message="Đang tải…" />;
  }

  if (session) {
    return <AuthRoutePlaceholder message="Đang chuyển vào hệ thống…" />;
  }

  return <>{children}</>;
}

src/components/shared/store-location-map.content:
"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { GoogleMap, Marker, useJsApiLoader } from "@react-google-maps/api";
import { Button } from "@ui/components/button";
import { Loader2, MapPin, MousePointerClick, Navigation } from "lucide-react";

const DEFAULT_CENTER = { lat: 10.762622, lng: 106.660172 };

const mapContainerClass = "w-full h-[380px] rounded-lg";

type Props = {
  /** Địa chỉ đang chỉnh (ô nhập + cập nhật từ bản đồ). */
  address: string;
  onAddressChange: (formattedAddress: string) => void;
  /**
   * Địa chỉ đã lưu trên server — chỉ để căn bản đồ khi `recenterSignal` đổi
   * (tránh geocode lại mỗi lần gõ phím).
   */
  snapshotAddress: string;
  /** Ví dụ `${user.id}-${user.updatedAt}` sau khi fetch/lưu. */
  recenterSignal: string;
  disabled?: boolean;
};

function MapFallbackEmbed({
  address,
  mapIframeUrl,
  mapExternalUrl,
}: {
  address: string;
  mapIframeUrl: string;
  mapExternalUrl: string;
}) {
  return (
    <div className="space-y-3">
      <p className="text-sm text-amber-800 dark:text-amber-200/90 bg-amber-500/10 border border-amber-500/25 rounded-lg px-3 py-2">
        Thêm biến môi trường{" "}
        <code className="text-xs font-mono">NEXT_PUBLIC_GOOGLE_MAPS_API_KEY</code>{" "}
        (Maps JavaScript API + Geocoding) để chọn vị trí trực tiếp trên bản đồ.
        Hiện đang hiển thị bản đồ nhúng theo địa chỉ đã nhập.
      </p>
      <div className="rounded-lg overflow-hidden border border-outline-variant/40 bg-muted/20">
        <iframe
          title="Google Map cửa hàng"
          src={mapIframeUrl}
          className={mapContainerClass}
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        />
      </div>
      <p className="text-xs text-muted-foreground">
        Địa chỉ dùng cho bản đồ: {address.trim() || "—"}
      </p>
      <a href={mapExternalUrl} target="_blank" rel="noreferrer" className="block">
        <Button variant="outline" className="w-full" type="button">
          Mở Google Maps trong tab mới
        </Button>
      </a>
    </div>
  );
}

function InteractiveMap({
  googleMapsApiKey,
  address,
  snapshotAddress,
  recenterSignal,
  onAddressChange,
  disabled,
  mapIframeUrl,
  mapExternalUrl,
}: Props & {
  googleMapsApiKey: string;
  mapIframeUrl: string;
  mapExternalUrl: string;
}) {
  const { isLoaded, loadError } = useJsApiLoader({
    id: "storesync-store-map",
    googleMapsApiKey,
    language: "vi",
    region: "VN",
  });

  const [marker, setMarker] = useState<google.maps.LatLngLiteral | null>(null);
  const [mapCenter, setMapCenter] =
    useState<google.maps.LatLngLiteral>(DEFAULT_CENTER);
  const [mapZoom, setMapZoom] = useState(13);
  const [geocoding, setGeocoding] = useState(false);
  const [map, setMap] = useState<google.maps.Map | null>(null);

  const reverseGeocode = useCallback(
    (latLng: google.maps.LatLngLiteral) => {
      if (!window.google?.maps) return;
      setGeocoding(true);
      const geocoder = new google.maps.Geocoder();
      geocoder.geocode({ location: latLng }, (results, status) => {
        setGeocoding(false);
        if (status !== "OK" || !results?.[0]?.formatted_address) {
          return;
        }
        onAddressChange(results[0].formatted_address);
      });
    },
    [onAddressChange],
  );

  const onMapClick = useCallback(
    (e: google.maps.MapMouseEvent) => {
      if (disabled || !e.latLng) return;
      const lat = e.latLng.lat();
      const lng = e.latLng.lng();
      const pos = { lat, lng };
      setMarker(pos);
      setMapCenter(pos);
      setMapZoom(16);
      reverseGeocode(pos);
    },
    [disabled, reverseGeocode],
  );

  const onMarkerDragEnd = useCallback(
    (e: google.maps.MapMouseEvent) => {
      if (disabled || !e.latLng) return;
      const lat = e.latLng.lat();
      const lng = e.latLng.lng();
      const pos = { lat, lng };
      setMarker(pos);
      reverseGeocode(pos);
    },
    [disabled, reverseGeocode],
  );

  const geocodeSearchText = useCallback(() => {
    const q = address.trim();
    if (!q || !window.google?.maps || disabled) return;
    setGeocoding(true);
    const geocoder = new google.maps.Geocoder();
    geocoder.geocode({ address: q, region: "VN" }, (results, status) => {
      setGeocoding(false);
      if (status !== "OK" || !results?.[0]?.geometry?.location) {
        return;
      }
      const loc = results[0].geometry.location;
      const pos = { lat: loc.lat(), lng: loc.lng() };
      setMarker(pos);
      setMapCenter(pos);
      setMapZoom(16);
      map?.panTo(pos);
      if (results[0].formatted_address) {
        onAddressChange(results[0].formatted_address);
      }
    });
  }, [address, disabled, map, onAddressChange]);

  /** Căn bản đồ theo địa chỉ đã lưu khi tải / sau khi lưu (không theo từng phím gõ). */
  useEffect(() => {
    if (!isLoaded || !window.google?.maps || disabled) return;
    const q = snapshotAddress.trim();
    if (!q) {
      setMarker(null);
      setMapCenter(DEFAULT_CENTER);
      setMapZoom(13);
      return;
    }
    const geocoder = new google.maps.Geocoder();
    let cancelled = false;
    geocoder.geocode({ address: q, region: "VN" }, (results, status) => {
      if (cancelled) return;
      if (status !== "OK" || !results?.[0]?.geometry?.location) return;
      const loc = results[0].geometry.location;
      const pos = { lat: loc.lat(), lng: loc.lng() };
      setMarker(pos);
      setMapCenter(pos);
      setMapZoom(15);
    });
    return () => {
      cancelled = true;
    };
  }, [isLoaded, disabled, recenterSignal, snapshotAddress]);

  if (loadError) {
    return (
      <MapFallbackEmbed
        address={address}
        mapIframeUrl={mapIframeUrl}
        mapExternalUrl={mapExternalUrl}
      />
    );
  }

  if (!isLoaded) {
    return (
      <div
        className={`${mapContainerClass} border border-outline-variant/40 bg-muted/30 flex flex-col items-center justify-center gap-2`}
      >
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
        <p className="text-sm text-muted-foreground">Đang tải bản đồ…</p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:justify-between">
        <p className="text-sm text-muted-foreground flex items-start gap-2">
          <MousePointerClick className="w-4 h-4 shrink-0 mt-0.5 text-primary" />
          <span>
            <strong className="text-foreground">Click</strong> trên bản đồ hoặc{" "}
            <strong className="text-foreground">kéo ghim</strong> để lấy địa chỉ
            chuẩn hoá; dùng nút bên cạnh để tìm theo nội dung ô địa chỉ.
          </span>
        </p>
        <Button
          type="button"
          variant="secondary"
          size="sm"
          className="shrink-0 rounded-lg"
          disabled={disabled || !address.trim() || geocoding}
          onClick={() => geocodeSearchText()}
        >
          {geocoding ? (
            <Loader2 className="w-4 h-4 animate-spin" />
          ) : (
            <Navigation className="w-4 h-4" />
          )}
          <span className="ml-2">Tìm theo ô địa chỉ</span>
        </Button>
      </div>

      <div className="relative rounded-lg overflow-hidden border border-outline-variant/40">
        {geocoding && (
          <div className="absolute inset-0 z-[1] bg-background/40 flex items-center justify-center pointer-events-none">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        )}
        <GoogleMap
          mapContainerClassName={mapContainerClass}
          center={mapCenter}
          zoom={mapZoom}
          onClick={onMapClick}
          onLoad={(m) => setMap(m)}
          options={{
            streetViewControl: false,
            mapTypeControl: false,
            fullscreenControl: true,
            gestureHandling: "greedy",
            clickableIcons: false,
          }}
        >
          {marker && (
            <Marker
              position={marker}
              draggable={!disabled}
              onDragEnd={onMarkerDragEnd}
              title="Vị trí cửa hàng"
            />
          )}
        </GoogleMap>
      </div>

      <div className="flex flex-wrap gap-2 items-center text-xs text-muted-foreground">
        <MapPin className="w-3.5 h-3.5" />
        <span>
          {marker
            ? `${marker.lat.toFixed(5)}, ${marker.lng.toFixed(5)}`
            : "Chưa chọn điểm trên bản đồ"}
        </span>
      </div>

      <a href={mapExternalUrl} target="_blank" rel="noreferrer" className="block">
        <Button variant="outline" className="w-full" type="button">
          Mở Google Maps trong tab mới
        </Button>
      </a>
    </div>
  );
}

/**
 * Bản đồ chọn địa chỉ cửa hàng: API key → Maps JS + Geocoding; không có key → iframe.
 */
export function StoreLocationMapPicker(props: Props) {
  const apiKey = process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY?.trim() ?? "";

  const mapQuery = useMemo(() => {
    const q =
      props.address.trim() ||
      props.snapshotAddress.trim() ||
      "Thành phố Hồ Chí Minh";
    return encodeURIComponent(q);
  }, [props.address, props.snapshotAddress]);
  const mapIframeUrl = `https://www.google.com/maps?q=${mapQuery}&output=embed`;
  const mapExternalUrl = `https://www.google.com/maps/search/?api=1&query=${mapQuery}`;

  if (!apiKey) {
    return (
      <MapFallbackEmbed
        address={props.address}
        mapIframeUrl={mapIframeUrl}
        mapExternalUrl={mapExternalUrl}
      />
    );
  }

  return (
    <InteractiveMap
      {...props}
      googleMapsApiKey={apiKey}
      mapIframeUrl={mapIframeUrl}
      mapExternalUrl={mapExternalUrl}
    />
  );
}

src/hooks/queries.ts.content:
"use client";

/**
 * Centralised TanStack Query hooks for the storefront.
 * Each hook owns its query-key and mutation invalidations so call sites stay
 * tiny: `const { data } = useProducts();`.
 */

import {
  useMutation,
  useQuery,
  useQueryClient,
  type UseMutationResult,
  type UseQueryResult,
} from "@tanstack/react-query";
import {
  api,
  type Category,
  type CategoryUsage,
  type CreateOrderInput,
  type Order,
  type OrderStatus,
  type Product,
  type ProductListParams,
  type ProductPagedResponse,
  type User,
  type UpdateProfileInput,
} from "@/lib/api";

export const queryKeys = {
  products: () => ["products"] as const,
  productsCatalog: (p: ProductListParams & { page: number; limit: number }) =>
    ["products", "catalog", p] as const,
  product: (id: number) => ["products", id] as const,
  productBySku: (sku: string) => ["products", "sku", sku] as const,
  productsByCategory: (slug: string) => ["products", "category", slug] as const,
  categories: (activeOnly?: boolean) =>
    ["categories", { activeOnly: !!activeOnly }] as const,
  category: (slug: string) => ["categories", "slug", slug] as const,
  categoryUsage: () => ["categories", "usage"] as const,
  orders: (email?: string) => ["orders", { email: email ?? null }] as const,
  order: (id: number) => ["orders", id] as const,
  user: (email: string) => ["users", "email", email] as const,
  userById: (id: number) => ["users", "id", id] as const,
};

/** Trang chủ / xem nhanh: toàn bộ SP đang bán (không phân trang). */
export const useProducts = (): UseQueryResult<Product[], Error> =>
  useQuery<Product[], Error>({
    queryKey: ["products", "active-all"],
    queryFn: async (): Promise<Product[]> => {
      const res = await api.products.list({ activeOnly: true });
      return Array.isArray(res) ? res : res.items;
    },
  });

/** Danh mục storefront: lọc + phân trang qua GET /products. */
export const useCatalogProducts = (
  params: ProductListParams & { page: number; limit: number },
) =>
  useQuery<ProductPagedResponse, Error>({
    queryKey: queryKeys.productsCatalog(params),
    queryFn: async () => {
      const res = await api.products.list(params);
      if (!res || Array.isArray(res)) {
        throw new Error("API phải trả { items, total } khi có page & limit");
      }
      return res;
    },
  });

export const useCategoryUsage = () =>
  useQuery<CategoryUsage[], Error>({
    queryKey: queryKeys.categoryUsage(),
    queryFn: () => api.categories.usage(),
  });

export const useProduct = (id: number | null | undefined) =>
  useQuery({
    queryKey: queryKeys.product(id ?? -1),
    queryFn: () => api.products.get(id as number),
    enabled: typeof id === "number" && id > 0,
  });

export const useProductBySku = (sku: string | null | undefined) =>
  useQuery({
    queryKey: queryKeys.productBySku(sku ?? ""),
    queryFn: () => api.products.bySku(sku as string),
    enabled: !!sku,
  });

export const useCategories = (activeOnly = false) =>
  useQuery<Category[], Error>({
    queryKey: queryKeys.categories(activeOnly),
    queryFn: async (): Promise<Category[]> => {
      const res = await api.categories.list({ activeOnly });
      return Array.isArray(res) ? res : res.items;
    },
  });

export const useCategoryBySlug = (slug: string | null | undefined) =>
  useQuery<Category, Error>({
    queryKey: queryKeys.category(slug ?? ""),
    queryFn: () => api.categories.bySlug(slug as string),
    enabled: !!slug,
  });

export const useOrders = (email?: string) =>
  useQuery<Order[], Error>({
    queryKey: queryKeys.orders(email),
    queryFn: async (): Promise<Order[]> => {
      const res = await api.orders.list({ email });
      return Array.isArray(res) ? res : res.items;
    },
    enabled: !!email?.trim(),
  });

export const useOrder = (id: number | null | undefined) =>
  useQuery<Order, Error>({
    queryKey: queryKeys.order(id ?? -1),
    queryFn: () => api.orders.get(id as number),
    enabled: typeof id === "number" && id > 0,
  });

export const useUserByEmail = (email: string | null | undefined) =>
  useQuery<User | null, Error>({
    queryKey: queryKeys.user(email ?? ""),
    queryFn: () => api.users.byEmail(email as string),
    enabled: !!email,
  });

/** Hồ sơ theo id — dùng cho đại lý (gửi X-User-Id); byEmail cần users.manage. */
export const useUserById = (id: number | null | undefined) =>
  useQuery<User, Error>({
    queryKey: queryKeys.userById(id ?? -1),
    queryFn: () => api.users.get(id as number),
    enabled: typeof id === "number" && id > 0,
  });

export const useUpdateProfile = (): UseMutationResult<
  User,
  Error,
  { id: number; input: UpdateProfileInput }
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, input }) => api.users.updateProfile(id, input),
    onSuccess: (user) => {
      qc.setQueryData(queryKeys.userById(user.id), user);
      void qc.invalidateQueries({ queryKey: ["users"] });
    },
  });
};

export const useCreateOrder = (): UseMutationResult<
  Order,
  Error,
  CreateOrderInput
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (input: CreateOrderInput) => api.orders.create(input),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["orders"] });
      void qc.invalidateQueries({ queryKey: ["products"] });
    },
  });
};

export const useUpdateOrderStatus = (): UseMutationResult<
  Order,
  Error,
  { id: number; status: OrderStatus; actor?: string }
> => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, status, actor }) =>
      api.orders.updateStatus(id, status, actor),
    onSuccess: (order) => {
      void qc.invalidateQueries({ queryKey: ["orders"] });
      qc.setQueryData(queryKeys.order(order.id), order);
    },
  });
};

src/hooks/use-cart.ts.content:
"use client";

import { useCallback, useSyncExternalStore } from "react";
import {
  applyPromoCodeWithRules,
  type PromoResult,
} from "@workspace/promo-codes";
import { getMergedPromoRules } from "@/lib/promo-rules-registry";
import { effectiveLineUnitPrice } from "@workspace/api-client";
import type { Product, ProductUnitType } from "@/lib/api";

const STORAGE_KEY = "storesync_cart_v1";

export interface CartLine {
  productId: number;
  sku: string;
  name: string;
  image?: string;
  category: string;
  unitType: string;
  unitLabel: string;
  /** Giá đang áp dụng theo SL (KM khi đủ minPromoQty). */
  unitPrice: number;
  /** Giá ban đầu cùng đơn vị (retail). */
  listUnitPrice: number;
  /** Giá KM trên đơn vị (wholesale < retail); null = không có tier KM. */
  promoUnitPrice: number | null;
  /** SL tối thiểu để áp promoUnitPrice (minWholesaleQty). */
  minPromoQty: number;
  qtyPerUnit: number;
  quantity: number;
  isWholesale: boolean;
  stock: number;
}

interface CartState {
  lines: CartLine[];
  appliedPromoCode: string | null;
}

const initialState: CartState = { lines: [], appliedPromoCode: null };

/** Khóa gộp dòng: cùng sản phẩm + cùng loại đơn vị (trim). */
export function cartLineKey(productId: number, unitType: string): string {
  return `${productId}:${String(unitType).trim()}`;
}

/** SL trong giỏ (cùng SP + loại đơn vị), để preview giá khi cộng với SL đang chọn trên catalog/CTSP. */
export function cartLineQuantity(
  lines: readonly CartLine[],
  productId: number,
  unitType: string,
): number {
  const key = cartLineKey(productId, unitType);
  const line = lines.find(
    (l) => cartLineKey(l.productId, l.unitType) === key,
  );
  return line ? Math.max(0, Math.floor(line.quantity)) : 0;
}

function repriceLine(line: CartLine): CartLine {
  const retail = Math.max(
    0,
    Math.floor(line.listUnitPrice ?? line.unitPrice),
  );
  const promoRaw = line.promoUnitPrice;
  const promo =
    promoRaw === null || promoRaw === undefined || !Number.isFinite(promoRaw)
      ? null
      : Math.floor(promoRaw);
  const minQ = Math.max(0, Math.floor(line.minPromoQty ?? 0));

  if (promo === null || promo <= 0 || promo >= retail) {
    return {
      ...line,
      listUnitPrice: retail,
      unitPrice: retail,
      promoUnitPrice: null,
      minPromoQty: minQ,
      isWholesale: false,
    };
  }

  const eff = effectiveLineUnitPrice(
    {
      retailPrice: retail,
      wholesalePrice: promo,
      minWholesaleQty: minQ,
    },
    line.quantity,
  );
  return {
    ...line,
    listUnitPrice: eff.listUnitPrice,
    unitPrice: eff.unitPrice,
    promoUnitPrice: promo,
    minPromoQty: minQ,
    isWholesale: eff.isSaleActive,
  };
}

function mergeDuplicateCartLines(lines: CartLine[]): CartLine[] {
  const map = new Map<string, CartLine>();
  for (const l of lines) {
    const key = cartLineKey(l.productId, l.unitType);
    const prev = map.get(key);
    if (!prev) {
      map.set(
        key,
        repriceLine(
          clamp({
            ...l,
            unitType: String(l.unitType).trim(),
            quantity: Math.max(1, Math.floor(l.quantity)),
          }),
        ),
      );
    } else {
      prev.quantity =
        Math.max(1, prev.quantity) + Math.max(1, Math.floor(l.quantity));
      prev.unitLabel = l.unitLabel;
      prev.qtyPerUnit = l.qtyPerUnit;
      prev.stock = l.stock;
      prev.promoUnitPrice = l.promoUnitPrice;
      prev.minPromoQty = l.minPromoQty;
      prev.listUnitPrice = l.listUnitPrice;
      if (l.image) prev.image = l.image;
      map.set(key, repriceLine(clamp(prev)));
    }
  }
  return [...map.values()];
}

/** Gộp dòng trùng trước khi POST tạo đơn (phòng trùng từ client). */
export function mergeLinesForCreateOrder(
  lines: CartLine[],
): Array<{ productId: number; quantity: number; unitType: string }> {
  const map = new Map<
    string,
    { productId: number; quantity: number; unitType: string }
  >();
  for (const l of lines) {
    const ut = String(l.unitType).trim();
    const key = cartLineKey(l.productId, ut);
    const prev = map.get(key);
    const q = Math.max(1, Math.floor(l.quantity));
    if (prev) prev.quantity += q;
    else map.set(key, { productId: l.productId, quantity: q, unitType: ut });
  }
  return [...map.values()];
}

function isCartLineCore(value: unknown): boolean {
  if (!value || typeof value !== "object") return false;
  const o = value as Record<string, unknown>;
  return (
    typeof o.productId === "number" &&
    typeof o.sku === "string" &&
    typeof o.name === "string" &&
    typeof o.category === "string" &&
    typeof o.unitType === "string" &&
    typeof o.unitLabel === "string" &&
    typeof o.unitPrice === "number" &&
    typeof o.qtyPerUnit === "number" &&
    typeof o.quantity === "number" &&
    typeof o.isWholesale === "boolean" &&
    typeof o.stock === "number"
  );
}

function normalizeCartState(raw: unknown): CartState {
  if (!raw || typeof raw !== "object") {
    return { lines: [], appliedPromoCode: null };
  }
  const o = raw as Record<string, unknown>;
  const linesRaw = o.lines;
  const linesIn = Array.isArray(linesRaw) ? linesRaw : [];
  const out: CartLine[] = [];
  for (const item of linesIn) {
    if (!isCartLineCore(item)) continue;
    const row = item as Record<string, unknown> & CartLine;
    const listUnitPrice =
      typeof row.listUnitPrice === "number" && Number.isFinite(row.listUnitPrice)
        ? Math.max(0, Math.floor(row.listUnitPrice))
        : Math.max(0, Math.floor(row.unitPrice));

    let promoUnitPrice: number | null = null;
    if (
      typeof row.promoUnitPrice === "number" &&
      Number.isFinite(row.promoUnitPrice)
    ) {
      promoUnitPrice = Math.floor(row.promoUnitPrice);
    } else if (listUnitPrice > Math.floor(row.unitPrice)) {
      promoUnitPrice = Math.floor(row.unitPrice);
    }

    let minPromoQty = 0;
    if (
      typeof row.minPromoQty === "number" &&
      Number.isFinite(row.minPromoQty)
    ) {
      minPromoQty = Math.max(0, Math.floor(row.minPromoQty));
    }

    const base: CartLine = {
      productId: row.productId,
      sku: row.sku,
      name: row.name,
      image: row.image,
      category: row.category,
      unitType: String(row.unitType).trim(),
      unitLabel: row.unitLabel,
      unitPrice: row.unitPrice,
      listUnitPrice,
      promoUnitPrice,
      minPromoQty,
      qtyPerUnit: row.qtyPerUnit,
      quantity: Math.max(1, Math.floor(row.quantity)),
      isWholesale: row.isWholesale,
      stock: row.stock,
    };
    out.push(repriceLine(clamp(base)));
  }
  let appliedPromoCode: string | null = null;
  if (typeof o.appliedPromoCode === "string" && o.appliedPromoCode.trim()) {
    appliedPromoCode = o.appliedPromoCode.trim().toUpperCase();
  }
  return { lines: mergeDuplicateCartLines(out), appliedPromoCode };
}

const isClient = typeof window !== "undefined";

const subscribers = new Set<() => void>();
let snapshot: CartState = initialState;

const read = (): CartState => {
  if (!isClient) return initialState;
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return { lines: [], appliedPromoCode: null };
    const parsed = JSON.parse(raw) as unknown;
    return normalizeCartState(parsed);
  } catch {
    return { lines: [], appliedPromoCode: null };
  }
};

const notify = (): void => {
  for (const cb of subscribers) cb();
};

const write = (next: CartState): void => {
  snapshot = next;
  if (isClient) {
    try {
      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
    } catch {
      // Storage might be full or disabled (private mode); the in-memory
      // snapshot is still updated so the UI stays consistent for the session.
    }
  }
  notify();
};

let crossTabBound = false;
const bindCrossTab = (): void => {
  if (!isClient || crossTabBound) return;
  crossTabBound = true;
  window.addEventListener("storage", (event) => {
    if (event.key !== STORAGE_KEY && event.key !== null) return;
    snapshot = read();
    notify();
  });
};

const subscribe = (cb: () => void): (() => void) => {
  subscribers.add(cb);
  bindCrossTab();
  return () => {
    subscribers.delete(cb);
  };
};

if (isClient) {
  snapshot = read();
}

function computeSubtotal(lines: CartLine[]): number {
  return lines.reduce((sum, l) => sum + l.unitPrice * l.quantity, 0);
}

const lineFromUnit = (
  product: Product,
  unit: ProductUnitType,
  quantity: number,
): CartLine => {
  const retail = Math.max(0, Math.floor(Number(unit.retailPrice) || 0));
  const rawW = unit.wholesalePrice;
  const promo =
    rawW === null || rawW === undefined || !Number.isFinite(Number(rawW))
      ? null
      : Math.floor(Number(rawW));
  const hasPromo = promo !== null && promo > 0 && promo < retail;
  const minPromoQty = Math.max(0, Math.floor(Number(unit.minWholesaleQty) || 0));
  const eff = effectiveLineUnitPrice(
    {
      retailPrice: retail,
      wholesalePrice: hasPromo ? promo : null,
      minWholesaleQty: minPromoQty,
    },
    quantity,
  );
  return {
    productId: product.id,
    sku: product.sku,
    name: product.name,
    image: product.images?.[0],
    category: product.category,
    unitType: String(unit.type).trim(),
    unitLabel: unit.label,
    unitPrice: eff.unitPrice,
    listUnitPrice: eff.listUnitPrice,
    promoUnitPrice: hasPromo ? promo : null,
    minPromoQty,
    qtyPerUnit: unit.qtyPerUnit,
    quantity,
    isWholesale: eff.isSaleActive,
    stock: product.stock,
  };
};

const clamp = (line: CartLine): CartLine => {
  const maxByStock = Math.max(
    1,
    Math.floor(line.stock / Math.max(line.qtyPerUnit, 1)),
  );
  const next = Math.max(1, Math.min(line.quantity, maxByStock));
  return { ...line, quantity: next };
};

export const cartStore = {
  getState: (): CartState => snapshot,
  /** Ghi đè giỏ (sau khi pull từ server). */
  replaceState(raw: unknown): void {
    write(normalizeCartState(raw));
  },
  add(product: Product, unit: ProductUnitType, quantity: number): void {
    if (quantity <= 0) return;
    const next = read();
    const key = cartLineKey(product.id, unit.type);
    const existing = next.lines.find(
      (l) => cartLineKey(l.productId, l.unitType) === key,
    );
    if (existing) {
      existing.quantity += quantity;
      existing.unitLabel = unit.label;
      existing.qtyPerUnit = unit.qtyPerUnit;
      existing.stock = product.stock;
      const fresh = lineFromUnit(product, unit, existing.quantity);
      existing.listUnitPrice = fresh.listUnitPrice;
      existing.promoUnitPrice = fresh.promoUnitPrice;
      existing.minPromoQty = fresh.minPromoQty;
      Object.assign(existing, repriceLine(clamp(existing)));
    } else {
      next.lines.push(repriceLine(clamp(lineFromUnit(product, unit, quantity))));
    }
    write(next);
  },
  setQuantity(productId: number, unitType: string, quantity: number): void {
    const next = read();
    const idx = next.lines.findIndex(
      (l) =>
        cartLineKey(l.productId, l.unitType) ===
        cartLineKey(productId, unitType),
    );
    if (idx === -1) return;
    if (quantity <= 0) {
      next.lines.splice(idx, 1);
    } else {
      const updated = repriceLine(
        clamp({ ...next.lines[idx]!, quantity }),
      );
      next.lines[idx] = updated;
    }
    write(next);
  },
  remove(productId: number, unitType: string): void {
    const next = read();
    next.lines = next.lines.filter(
      (l) =>
        cartLineKey(l.productId, l.unitType) !==
        cartLineKey(productId, unitType),
    );
    write(next);
  },
  clear(): void {
    write({ lines: [], appliedPromoCode: null });
  },
  applyPromo(raw: string): PromoResult {
    const next = read();
    const subtotal = computeSubtotal(next.lines);
    const cartLines = next.lines.map((l) => ({
      unitType: l.unitType,
      quantity: l.quantity,
    }));
    const result = applyPromoCodeWithRules(
      subtotal,
      raw,
      getMergedPromoRules(),
      {
        cartLines,
        preAppliedDiscount: 0,
      },
    );
    if (!result.ok) return result;
    next.appliedPromoCode = result.normalizedCode;
    write(next);
    return result;
  },
  clearPromo(): void {
    const next = read();
    next.appliedPromoCode = null;
    write(next);
  },
};

export interface CartSummary {
  lines: CartLine[];
  itemCount: number;
  unitCount: number;
  /** Tạm tính theo giá đang áp dụng (KM theo đơn vị + SL). */
  subtotal: number;
  /** So với giá ban đầu cùng đơn vị (chỉ hiển thị khi > 0). */
  wholesaleSavings: number;
  appliedPromoCode: string | null;
  promoDiscount: number;
  promoLabel: string | null;
  /** Mã đang lưu nhưng không đủ điều kiện sau khi đổi giỏ. */
  promoError: string | null;
  /** Thành tiền tạm (sau mã coupon nếu có; KM đơn vị đã nằm trong tạm tính). */
  grandTotal: number;
  /** Mã gửi lên API khi đặt hàng (chỉ khi hợp lệ). */
  couponCodeForOrder: string | undefined;
  add: (product: Product, unit: ProductUnitType, quantity?: number) => void;
  setQuantity: (productId: number, unitType: string, quantity: number) => void;
  remove: (productId: number, unitType: string) => void;
  clear: () => void;
  applyPromo: (raw: string) => PromoResult;
  clearPromo: () => void;
}

export function useCart(): CartSummary {
  const state = useSyncExternalStore(
    subscribe,
    () => snapshot,
    () => initialState,
  );

  const add = useCallback(
    (product: Product, unit: ProductUnitType, quantity = 1) =>
      cartStore.add(product, unit, quantity),
    [],
  );
  const setQuantity = useCallback(
    (productId: number, unitType: string, quantity: number) =>
      cartStore.setQuantity(productId, unitType, quantity),
    [],
  );
  const remove = useCallback(
    (productId: number, unitType: string) =>
      cartStore.remove(productId, unitType),
    [],
  );
  const clear = useCallback(() => cartStore.clear(), []);
  const applyPromo = useCallback((raw: string) => cartStore.applyPromo(raw), []);
  const clearPromo = useCallback(() => cartStore.clearPromo(), []);

  const lines = state.lines;
  const itemCount = lines.length;
  const unitCount = lines.reduce((sum, l) => sum + l.quantity, 0);
  const subtotal = computeSubtotal(lines);
  const wholesaleSavings = lines.reduce((sum, l) => {
    const list = l.listUnitPrice ?? l.unitPrice;
    return sum + Math.max(0, list - l.unitPrice) * l.quantity;
  }, 0);

  const cartLines = lines.map((l) => ({
    unitType: l.unitType,
    quantity: l.quantity,
  }));

  const appliedPromoCode = state.appliedPromoCode;
  const promoEval = appliedPromoCode
    ? applyPromoCodeWithRules(
        subtotal,
        appliedPromoCode,
        getMergedPromoRules(),
        {
          cartLines,
          preAppliedDiscount: 0,
        },
      )
    : null;
  const promoDiscount = promoEval?.ok === true ? promoEval.discount : 0;
  const promoLabel = promoEval?.ok === true ? promoEval.label : null;
  const promoError =
    appliedPromoCode && promoEval?.ok === false ? promoEval.message : null;
  const grandTotal = Math.max(0, subtotal - promoDiscount);
  const couponCodeForOrder =
    appliedPromoCode && promoEval?.ok === true
      ? promoEval.normalizedCode
      : undefined;

  return {
    lines,
    itemCount,
    unitCount,
    subtotal,
    wholesaleSavings,
    appliedPromoCode,
    promoDiscount,
    promoLabel,
    promoError,
    grandTotal,
    couponCodeForOrder,
    add,
    setQuantity,
    remove,
    clear,
    applyPromo,
    clearPromo,
  };
}

src/hooks/use-client-ready.ts.content:
"use client";

import { useSyncExternalStore } from "react";

const noopSubscribe = () => () => {};

/**
 * `false` khi render trên server / trước hydrate, `true` trên client.
 * Dùng thay vì `useEffect` + `setState` để tránh cảnh báo ESLint.
 */
export function useClientReady(): boolean {
  return useSyncExternalStore(noopSubscribe, () => true, () => false);
}

src/hooks/use-debounced-value.ts.content:
"use client";

import { useEffect, useState } from "react";

/**
 * Trì hoãn cập nhật giá trị (tìm kiếm, sync URL) để giảm render / request.
 */
export function useDebouncedValue<T>(value: T, delayMs: number): T {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const t = window.setTimeout(() => setDebounced(value), delayMs);
    return () => window.clearTimeout(t);
  }, [value, delayMs]);

  return debounced;
}

src/hooks/use-graphify.ts.content:
"use client";

import { useState, useCallback } from "react";
import type { GraphifyPayload, GraphNode } from "@/lib/graphify-context";
import { getLinkedNodes, communityBreakdown, topHubs, routeFiles } from "@/lib/graphify-context";

export interface UseGraphifyReturn {
  data: GraphifyPayload | null;
  loading: boolean;
  error: string | null;
  selectedNode: GraphNode | null;
  setSelectedNode: (n: GraphNode | null) => void;
  linkedNodes: Map<string, number>;
  communities: ReturnType<typeof communityBreakdown>;
  hubs: ReturnType<typeof topHubs>;
  routes: ReturnType<typeof routeFiles>;
  refresh: () => Promise<void>;
}

export function useGraphify(maxDegree = 1): UseGraphifyReturn {
  const [data, setData] = useState<GraphifyPayload | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/graphify");
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const payload: GraphifyPayload = await res.json();
      setData(payload);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Unknown error");
    } finally {
      setLoading(false);
    }
  }, []);

  const linkedNodes = selectedNode && data
    ? getLinkedNodes(selectedNode.id, data.graph, maxDegree)
    : new Map<string, number>();

  return {
    data,
    loading,
    error,
    selectedNode,
    setSelectedNode,
    linkedNodes,
    communities: data ? communityBreakdown(data.graph) : [],
    hubs: data ? topHubs(data.context) : [],
    routes: data ? routeFiles(data.context) : [],
    refresh,
  };
}

src/hooks/use-mobile.ts.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean>(
    () => typeof window !== "undefined" && window.innerWidth < MOBILE_BREAKPOINT
  )

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return isMobile
}

src/hooks/use-session.ts.content:
"use client";

import { useMemo, useSyncExternalStore } from "react";

export type MockSession = {
  id: string;
  username: string;
  role: "admin" | "store";
  displayName: string;
};

const STORAGE_KEY = "storesync_session";

function getSnapshot(): string | null {
  if (typeof window === "undefined") return null;
  return window.localStorage.getItem(STORAGE_KEY);
}

function getServerSnapshot(): string | null {
  return null;
}

function subscribe(callback: () => void) {
  if (typeof window === "undefined") return () => {};
  const onStorage = (event: StorageEvent) => {
    if (event.key === STORAGE_KEY || event.key === null) callback();
  };
  const onCustom = () => callback();
  window.addEventListener("storage", onStorage);
  window.addEventListener("storesync-session", onCustom);
  return () => {
    window.removeEventListener("storage", onStorage);
    window.removeEventListener("storesync-session", onCustom);
  };
}

export function useSession(): MockSession | null {
  const raw = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
  return useMemo(() => {
    if (!raw) return null;
    try {
      return JSON.parse(raw) as MockSession;
    } catch {
      return null;
    }
  }, [raw]);
}

