import type { ProductUnitType } from "@/lib/api";
import { effectiveLineUnitPrice } from "@workspace/api-client";

/**
 * Giá hiển thị (`current`) và giá gạch (`list`) tại một số lượng dòng cụ thể —
 * KM theo đơn vị chỉ khi đủ `minWholesaleQty` (cấu hình trên từng SP / từng loại hàng).
 */
export function unitSellingAndListPrice(
  unit: ProductUnitType,
  quantity = 1,
): {
  current: number;
  list: number | null;
} {
  const { unitPrice, listUnitPrice, isSaleActive } = effectiveLineUnitPrice(
    unit,
    quantity,
  );
  return {
    current: unitPrice,
    list: isSaleActive && listUnitPrice > unitPrice ? listUnitPrice : null,
  };
}

